package com.example.batchschedulers.model;

import jakarta.persistence.*;

import java.math.BigDecimal;
import java.time.LocalDateTime;

/**
 * JPA entity representing a summary report snapshot generated by the
 * {@code reportGenerationJob} batch job.
 *
 * <p>Each time the report generation job runs, it reads all products, computes
 * summary statistics, and persists one {@code ProductReport} row per category.
 * This gives a historical time-series of category-level inventory and pricing
 * without modifying the underlying product data.
 *
 * <p>Fields:
 * <ul>
 *   <li>{@code category}        – product category this row summarises</li>
 *   <li>{@code productCount}    – total number of products in that category</li>
 *   <li>{@code totalStock}      – sum of {@code stockQuantity} across all products</li>
 *   <li>{@code averagePrice}    – mean price across all products</li>
 *   <li>{@code lowStockCount}   – number of products currently flagged as low-stock</li>
 *   <li>{@code generatedAt}     – when this report snapshot was created</li>
 * </ul>
 *
 * <p>The table {@code product_reports} is created by Flyway migration V3.
 */
@Entity
@Table(name = "product_reports")
public class ProductReport {

    /**
     * Auto-generated surrogate primary key.
     */
    @Id
    @GeneratedValue(strategy = GenerationType.SEQUENCE, generator = "product_report_seq")
    @SequenceGenerator(name = "product_report_seq", sequenceName = "product_reports_id_seq", allocationSize = 1)
    private Long id;

    /**
     * Product category this report row covers (e.g. "Electronics").
     */
    @Column(nullable = false)
    private String category;

    /**
     * Total number of products in this category at the time the report was generated.
     */
    @Column(name = "product_count", nullable = false)
    private int productCount;

    /**
     * Sum of stock quantities across all products in this category.
     */
    @Column(name = "total_stock", nullable = false)
    private int totalStock;

    /**
     * Average unit price across all products in this category,
     * rounded to 2 decimal places.
     */
    @Column(name = "average_price", nullable = false, precision = 10, scale = 2)
    private BigDecimal averagePrice;

    /**
     * Number of products in this category that have the {@code lowStock} flag set.
     */
    @Column(name = "low_stock_count", nullable = false)
    private int lowStockCount;

    /**
     * Timestamp when this report snapshot was generated.
     */
    @Column(name = "generated_at", nullable = false)
    private LocalDateTime generatedAt;

    // ── Constructors ──────────────────────────────────────────────────────────

    /** Required by JPA. */
    protected ProductReport() {}

    /**
     * Convenience constructor for creating a new report row.
     *
     * @param category      product category
     * @param productCount  number of products
     * @param totalStock    total units in stock
     * @param averagePrice  average unit price
     * @param lowStockCount number of low-stock products
     */
    public ProductReport(String category, int productCount, int totalStock,
                         BigDecimal averagePrice, int lowStockCount) {
        this.category = category;
        this.productCount = productCount;
        this.totalStock = totalStock;
        this.averagePrice = averagePrice;
        this.lowStockCount = lowStockCount;
        this.generatedAt = LocalDateTime.now();
    }

    // ── Getters and setters ───────────────────────────────────────────────────

    public Long getId() { return id; }

    public String getCategory() { return category; }
    public void setCategory(String category) { this.category = category; }

    public int getProductCount() { return productCount; }
    public void setProductCount(int productCount) { this.productCount = productCount; }

    public int getTotalStock() { return totalStock; }
    public void setTotalStock(int totalStock) { this.totalStock = totalStock; }

    public BigDecimal getAveragePrice() { return averagePrice; }
    public void setAveragePrice(BigDecimal averagePrice) { this.averagePrice = averagePrice; }

    public int getLowStockCount() { return lowStockCount; }
    public void setLowStockCount(int lowStockCount) { this.lowStockCount = lowStockCount; }

    public LocalDateTime getGeneratedAt() { return generatedAt; }
    public void setGeneratedAt(LocalDateTime generatedAt) { this.generatedAt = generatedAt; }

    @Override
    public String toString() {
        return "ProductReport{id=" + id + ", category='" + category + "', productCount=" +
               productCount + ", totalStock=" + totalStock + ", averagePrice=" +
               averagePrice + ", lowStockCount=" + lowStockCount + ", generatedAt=" + generatedAt + "}";
    }
}
